  3019 | // (icmp eq X, 0) | (icmp ult Other, X) -> (icmp ule Other, X-1)
  3020 | // (icmp ne X, 0) & (icmp uge Other, X) -> (icmp ugt Other, X-1)
  3021 | static Value *foldAndOrOfICmpEqZeroAndICmp(ICmpInst *LHS, ICmpInst *RHS,
  3022 |                                            bool IsAnd, bool IsLogical,
  3023 |                                            IRBuilderBase &Builder) {
  3024 |   ICmpInst::Predicate LPred =
  3025 |       IsAnd ? LHS->getInversePredicate() : LHS->getPredicate();
  3026 |   ICmpInst::Predicate RPred =
  3027 |       IsAnd ? RHS->getInversePredicate() : RHS->getPredicate();
  3028 |   Value *LHS0 = LHS->getOperand(0);
  3029 |   if (LPred != ICmpInst::ICMP_EQ || !match(LHS->getOperand(1), m_Zero()) ||
  3030 |       !LHS0->getType()->isIntOrIntVectorTy() ||
  3031 |       !(LHS->hasOneUse() || RHS->hasOneUse()))
  3032 |     return nullptr;
  3033 | 
  3034 |   Value *Other;
  3035 |   if (RPred == ICmpInst::ICMP_ULT && RHS->getOperand(1) == LHS0)
  3036 |     Other = RHS->getOperand(0);
  3037 |   else if (RPred == ICmpInst::ICMP_UGT && RHS->getOperand(0) == LHS0)
  3038 |     Other = RHS->getOperand(1);
  3039 |   else
  3040 |     return nullptr;
  3041 | 
  3042 |   if (IsLogical)
  3043 |     Other = Builder.CreateFreeze(Other);
  3044 |   return Builder.CreateICmp(
  3045 |       IsAnd ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE,
  3046 |       Builder.CreateAdd(LHS0, Constant::getAllOnesValue(LHS0->getType())),
  3047 |       Other);
  3048 | }
