  3050 | /// Fold (icmp)&(icmp) or (icmp)|(icmp) if possible.
  3051 | /// If IsLogical is true, then the and/or is in select form and the transform
  3052 | /// must be poison-safe.
  3053 | Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
  3054 |                                           Instruction &I, bool IsAnd,
  3055 |                                           bool IsLogical) {
