  3057 | 
  3058 |   // Fold (iszero(A & K1) | iszero(A & K2)) ->  (A & (K1 | K2)) != (K1 | K2)
  3059 |   // Fold (!iszero(A & K1) & !iszero(A & K2)) ->  (A & (K1 | K2)) == (K1 | K2)
  3060 |   // if K1 and K2 are a one-bit mask.
  3061 |   if (Value *V = foldAndOrOfICmpsOfAndWithPow2(LHS, RHS, &I, IsAnd, IsLogical))
  3062 |     return V;
  3063 | 
  3064 |   ICmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();
  3065 |   Value *LHS0 = LHS->getOperand(0), *RHS0 = RHS->getOperand(0);
  3066 |   Value *LHS1 = LHS->getOperand(1), *RHS1 = RHS->getOperand(1);
  3067 |   const APInt *LHSC = nullptr, *RHSC = nullptr;
  3068 |   match(LHS1, m_APInt(LHSC));
  3069 |   match(RHS1, m_APInt(RHSC));
  3070 | 
  3071 |   // (icmp1 A, B) | (icmp2 A, B) --> (icmp3 A, B)
  3072 |   // (icmp1 A, B) & (icmp2 A, B) --> (icmp3 A, B)
  3073 |   if (predicatesFoldable(PredL, PredR)) {
  3074 |     if (LHS0 == RHS1 && LHS1 == RHS0) {
  3075 |       PredL = ICmpInst::getSwappedPredicate(PredL);
  3076 |       std::swap(LHS0, LHS1);
  3077 |     }
  3078 |     if (LHS0 == RHS0 && LHS1 == RHS1) {
  3079 |       unsigned Code = IsAnd ? getICmpCode(PredL) & getICmpCode(PredR)
  3080 |                             : getICmpCode(PredL) | getICmpCode(PredR);
  3081 |       bool IsSigned = LHS->isSigned() || RHS->isSigned();
  3082 |       return getNewICmpValue(Code, IsSigned, LHS0, LHS1, Builder);
  3083 |     }
  3084 |   }
  3085 | 
  3086 |   // handle (roughly):
  3087 |   // (icmp ne (A & B), C) | (icmp ne (A & D), E)
  3088 |   // (icmp eq (A & B), C) & (icmp eq (A & D), E)
  3089 |   if (Value *V = foldLogOpOfMaskedICmps(LHS, RHS, IsAnd, IsLogical, Builder))
