  3096 |   // the LHS, and as such poison from both will propagate.
  3097 |   if (Value *V = foldAndOrOfICmpEqZeroAndICmp(RHS, LHS, IsAnd,
  3098 |                                               /*IsLogical*/ false, Builder))
